using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;

int c[128][128], a[110], l, b[110], bl;
string s;
stack <int> f;
stack <int> h;


signed main(void)
{
	c['+']['+'] = 1;
	c['+']['-'] = 1;
	c['+']['*'] = 0;
	c['+']['/'] = 0;
	c['+']['^'] = 0;
	c['-']['+'] = 1;
	c['-']['-'] = 1;
	c['-']['*'] = 0;
	c['-']['/'] = 0;
	c['-']['^'] = 0;
	c['*']['+'] = 1;
	c['*']['-'] = 1;
	c['*']['*'] = 1;
	c['*']['/'] = 1;
	c['*']['^'] = 0;
	c['/']['+'] = 1;
	c['/']['-'] = 1;
	c['/']['*'] = 1;
	c['/']['/'] = 1;
	c['/']['^'] = 0;
	c['^']['+'] = 1;
	c['^']['-'] = 1;
	c['^']['*'] = 1;
	c['^']['/'] = 1;
	c['^']['^'] = 0;
	cin >> s;
	for (int i = 0; i < s.size(); i++)
	{
		if (s[i] >= '0' && s[i] <= '9')
		{
			int w = s[i] - '0';
			cout << w << " ";
			h.push(w);
		}
		else if (s[i] == '(')
		{
			f.push(s[i]);
		}
		else if (s[i] == ')')
		{
			while (f.top() != '(')
			{
				cout << (char) f.top() << " ";
				h.push(f.top());
				f.pop();
			}
			f.pop();
		}
		else
		{
			while (!f.empty() && c[f.top()][s[i]] == 1)
			{
				cout << (char) f.top() << " ";
				h.push(f.top());
				f.pop();
			}
			f.push(s[i]);
		}
	}
	while (!f.empty())
	{
		cout << (char) f.top() << " ";
		h.push(f.top());
		f.pop();
	}
	while (!h.empty())
	{
		f.push(h.top());
		h.pop();
	}
	cout << endl;
	while (!f.empty())
	{
		if (f.top() >= '0' && f.top() <= '9')
		{
			a[++l] = (int)(f.top() + 48);
		}
		else
		{
			a[++l] = (int)(f.top());
		}
		f.pop();
	}
	//return 0;
	while (1)
	{
		stack <int> ff;
		memset(b, 0, sizeof(b));
		bl = 0;
		for (int i = 1; i <= l; i++)
		{
			if ((a[i] == '+' || a[i] == '-' || a[i] == '*' || a[i] == '/' || a[i] == '^')&&ff.size() >= 2)
			{
				int x = ff.top();
				ff.pop();
				int y = ff.top();
				ff.pop();
				if (a[i] == '+')
				{
					ff.push(y + x);
				}
				else if (a[i] == '-')
				{
					ff.push(y - x);
				}
				else if (a[i] == '*')
				{
					ff.push(y * x);
				}
				else if (a[i] == '/')
				{
					ff.push(y / x);
				}
				else
				{
					ff.push(pow(y, x));
				}
				for (int j = 1; j <= i - 3; j++)
				{
					if (a[j] != '+' && a[j] != '-' && a[j] != '/' && a[j] != '*' && a[j] != '^')
					{
						cout << a[j] << " ";
					}
					else
					{
						cout << (char)a[j] << " ";
					}
					b[++bl] = a[j];
				}
				cout << ff.top() << " ";
				b[++bl] = ff.top();
				for (int j = i + 1; j <= l; j++)
				{
					if (a[j] != '+' && a[j] != '-' && a[j] != '/' && a[j] != '*' && a[j] != '^')
					{
						cout << a[j] << " ";
					}
					else
					{
						cout << (char)a[j] << " ";
					}
					b[++bl] = a[j];
				}
				cout << endl;
				for (int j = 1; j <= bl; j++)
				{
					a[j] = b[j];
				}
				l = bl;
				break;
			}
			else
			{
				ff.push(a[i]);
			}
		}
		if (bl == 1)
		{
			break;
		}
	}
	return false;
}
